function ns:DiffSummariesEqual(a,b)
  if type(a)~="table" or type(b)~="table" then return false end
  for _,key in ipairs({"changed","identical","skipped","unavailable","failed"}) do if a[key]~=b[key] then return false end end
  return true
end
